IMG_DIR = ROOT / f"projects/{PROJECT_NAME}/images"
IMG_DIR.mkdir(parents=True, exist_ok=True)


def generate_image(name, characters, prompt, api_key):
    """Generate a single image using Gemini, with character reference images."""
    from google import genai
    from google.genai import types

    client = genai.Client(api_key=api_key)

    try:
        contents = []
        # Attach each requested character reference as an inline_data part
        for char in characters:
            if char in REF_IMAGES:
                contents.append(types.Part.from_bytes(
                    data=REF_IMAGES[char]["bytes"],
                    mime_type=REF_IMAGES[char]["mime"],
                ))
        if contents:
            ref_desc = ", ".join(_CHARACTER_LABELS[c] for c in characters if c in _CHARACTER_LABELS)
            ring_note = ""
            if "joseph" in characters or "jess" in characters:
                ring_note = " Note: Joseph wears a simple gold wedding band on his left ring finger. Jess wears a modest diamond ring on her left ring finger. The rings are subtle, not shiny or sparkly — just there."
            contents.append(
                f"Using the attached images as character references ({ref_desc}), "
                f"generate this scene in the EXACT same art style (Boondocks-style animation, "
                f"bold linework, flat cel-shading). Each character must look like their reference.{ring_note} "
                f"Scene: {prompt}"
            )
        else:
            contents = [f"Generate this scene: {prompt}"]

        response = client.models.generate_content(
            model=MODEL,
            contents=contents,
            config=types.GenerateContentConfig(
                response_modalities=["IMAGE", "TEXT"],
                temperature=0.7,
                tools=[types.Tool(google_search=types.GoogleSearch())],
                image_config=types.ImageConfig(
                    image_size="4K",
                    aspect_ratio="16:9",
                ),
            ),
        )

        for part in response.candidates[0].content.parts:
            if part.inline_data is not None:
                img_data = part.inline_data.data
                mime = part.inline_data.mime_type
                ext = "png" if "png" in mime else "jpg"
                out_path = IMG_DIR / f"{name}.{ext}"
                if isinstance(img_data, str):
                    img_bytes = base64.b64decode(img_data)
                else:
                    img_bytes = img_data
                with open(out_path, "wb") as f:
                    f.write(img_bytes)
                cost = log_gemini_image_cost(IMG_DIR.parent, 1, name)
                print(f"  OK {name} → {out_path} ({len(img_bytes) // 1024} KB, cost: ${cost:.4f})")
                return name, str(out_path), ext
        return name, None, "No image in response"
    except Exception as e:
        print(f"  FAIL {name}: {e}")
        return name, None, str(e)


def main():
    remaining = []
    for name, characters, prompt in IMAGES:
        if (IMG_DIR / f"{name}.png").exists() or (IMG_DIR / f"{name}.jpg").exists():
            print(f"  SKIP {name} (exists)")
        else:
            remaining.append((name, characters, prompt))

    if not remaining:
        print("All images already generated!")
        return

    print(f"\nGenerating {len(remaining)} images using {MODEL}...\n")

    results = {}
    batch_size = len(API_KEYS)
    for batch_start in range(0, len(remaining), batch_size):
        batch = remaining[batch_start:batch_start + batch_size]
        if batch_start > 0:
            print(f"\n  -- Waiting 15s between batches to avoid rate limits --\n")
            time.sleep(15)

        with concurrent.futures.ThreadPoolExecutor(max_workers=len(batch)) as executor:
            futures = {}
            for i, (name, characters, prompt) in enumerate(batch):
                key = API_KEYS[i % len(API_KEYS)]
                futures[executor.submit(generate_image, name, characters, prompt, key)] = name

            for future in concurrent.futures.as_completed(futures):
                name, path, info = future.result()
                results[name] = (path, info)

    print(f"\n=== Summary ===")
    ok = sum(1 for p, _ in results.values() if p)
    print(f"  Generated: {ok}/{len(remaining)}")
    for name, (path, info) in sorted(results.items()):
        status = f"OK → {path}" if path else f"FAIL: {info}"
        print(f"  {name}: {status}")


if __name__ == "__main__":
    print(f"=== Generating images for project: {PROJECT_NAME} ===")
    main()
